class Solution {
public:
    int maxValue(int n, int index, int maxSum) {
        long long left = 1, right = maxSum, ans = 0;
        while (left <= right) {
            long long mid = left + (right - left) / 2;
            long long sum = mid;
            long long leftLen = index;
            long long rightLen = n - index - 1;

            // left side
            if (mid > leftLen) {
                sum += (mid - 1 + mid - leftLen) * leftLen / 2;
            } else {
                sum += (mid - 1) * mid / 2 + (leftLen - mid + 1);
            }

            // right side
            if (mid > rightLen) {
                sum += (mid - 1 + mid - rightLen) * rightLen / 2;
            } else {
                sum += (mid - 1) * mid / 2 + (rightLen - mid + 1);
            }

            if (sum <= maxSum) {
                ans = mid;
                left = mid + 1;
            } else {
                right = mid - 1;
            }
        }
        return ans;
    }
};
